def check():
    try:
        circuit = stim.Circuit.from_file("C:/Users/anpaz/Repos/quantum-ai/rq3/baseline_challenge.stim")
        sim = stim.TableauSimulator()
        sim.do(circuit)
        
        all_preserved = True
        for i, s in enumerate(stabilizers):
            p = stim.PauliString(s)
            # peek_observable_expectation returns 1, -1, or 0
            val = sim.peek_observable_expectation(p)
            if val != 1:
                print(f"Stabilizer {i} NOT preserved. Expectation: {val}")
                all_preserved = False
                # break
        
        if all_preserved:
            print("All stabilizers preserved by baseline.")
        else:
            print("Some stabilizers NOT preserved by baseline.")

        # Also, let's see what the tableau looks like.
        # Maybe we can extract the canonical stabilizers from the simulator
        # and see if they are equivalent to the target ones (or a superset).
        
    except Exception as e:
        print(f"Error: {e}")

if __name__ == "__main__":
    check()
